import 'dart:async'; import 'package:injectable/injectable.dart'; import '../../auto_connect/service/device_online_watcher.dart'; import '../../auto_connect/model/trusted_device.dart'; import '../../../core/utils/app_logger.dart'; @injectable class TrustedDevicePresenceWatcher { final DeviceOnlineWatcher _watcher; final Map<String, StreamSubscription> _subs = {}; TrustedDevicePresenceWatcher(this._watcher); void watch(List<TrustedDevice> devices, void Function(String, bool) onStatusChange) { for (final d in devices) { _subs[d.deviceId]?.cancel(); _subs[d.deviceId] = _watcher.watch(d).listen((online) { AppLogger.debug('Presence: ${d.deviceName} = $online'); onStatusChange(d.deviceId, online); }); } } void dispose() { for (final s in _subs.values) s.cancel(); _subs.clear(); } }